h2-step-2-accept-purchases-p5f308966.translation:
```swift
import Adapty

func purchaseProduct(_ product: AdaptyPaywallProduct) {
    Adapty.makePurchase(product: product) { result in
        switch result {
        case let .success(purchaseResult):
            switch purchaseResult {
            case .userCancelled:
                // Пользователь отменил покупку
                break
            case .pending:
                // Покупка ожидает подтверждения (например, ожидает родительского одобрения)
                break
            case let .success(profile, transaction):
                // Покупка успешна, профиль обновлён
                break
            }
        case let .failure(error):
            // Обработка ошибки
        }
    }
}
